arguments.command:
DBG=/tmp/symbols/libmonosgen-2.0.so.dbg

# Find nearest named function symbols (filtering out ARM mapping symbols $d, $x, $t)
echo "=== SGen worker - nearest named functions ==="
for addr in 0x2f4b20 0x2f4c84; do
  echo -n "  pc $addr => "
  nm -C "$DBG" 2>/dev/null | grep -v '^\s*$' | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target) }
    /^[0-9a-f]+ [tTwW]/ {
      name = $3
      for (i=4; i<=NF; i++) name = name " " $i
      if (name ~ /^\$[dxt]/) next
      sym_addr = strtonum("0x" $1)
      if (sym_addr <= target_dec && sym_addr > best_addr) {
        best_addr = sym_addr
        best_name = name
      }
    }
    END { if (best_name != "") printf "%s+0x%x\n", best_name, target_dec - best_addr; else print "not found" }
  '
done

