arguments.command:
DBG=/tmp/symbols/libmonosgen-2.0.so.dbg

# These addresses fall in a Cortex-A53 erratum patch section (linker-generated thunks)
# Let's see what the thunks branch to by disassembling
# We need aarch64 objdump for this
which aarch64-linux-gnu-objdump 2>/dev/null || echo "No cross objdump"

# Try readelf to look at DWARF line info for these addresses
readelf --debug-dump=line "$DBG" 2>/dev/null | head -5
echo "DWARF info present: $(readelf -S "$DBG" 2>/dev/null | grep -c debug)"

# Alternative: look at what section these addresses are in
readelf -S "$DBG" 2>/dev/null | awk '
  /\.text|cortex|errata/ { print }
' | head -10

# Let's try to find the actual functions using DWARF info via addr2line with the main .so
# The thunk addresses in the erratum section redirect to the real function
# Let's check the sections around these addresses
readelf -S "$DBG" 2>/dev/null | awk '
  /\[/ {
    if (match($0, /\] [^ ]+/)) {
      name = substr($0, RSTART+2, RLENGTH-2)
    }
    for (i=1; i<=NF; i++) {
      if ($i ~ /^[0-9a-f]{6,}$/ && length($i) >= 6) {
        addr = strtonum("0x" $i)
        if (addr > 0 && addr < 0x1000000) {
          # Found potential section address
        }
      }
    }
  }
' 

# Just show all sections with addresses
readelf -S "$DBG" 2>/dev/null | grep -E 'PROGBITS|NOBITS' | head -20

