arguments.command:
SO=/tmp/symbols/libmonosgen-2.0.so
# Check the actual binary's sections for the SGen worker addresses
readelf -S "$SO" 2>/dev/null | grep -E 'PROGBITS|NOBITS' | head -25
echo "---"
# Check what section contains 0x2f4b20
readelf -S "$SO" 2>/dev/null | awk '
  /PROGBITS|NOBITS/ {
    for (i=1; i<=NF; i++) {
      if ($i ~ /^[0-9a-f]{8,}$/) {
        addr = strtonum("0x" $i)
        if (addr > 0x80000 && addr < 0x400000) {
          start = addr
          for (j=i+1; j<=NF; j++) {
            if ($j ~ /^[0-9a-f]{5,}$/) {
              size = strtonum("0x" $j)
              if (size > 0x1000) {
                end = start + size
                if (0x2f4b20 >= start && 0x2f4b20 < end) {
                  print "0x2f4b20 is in section: " $0
                }
                break
              }
            }
          }
        }
      }
    }
  }
'

